# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy data for demonstration purposes
users = {
    'user1': {'email': 'old_email@example.com', 'password': 'old_password', '2fa_enabled': False}
}

@app.route('/profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    username = session['username']
    data = request.get_json()

    if 'email' in data:
        users[username]['email'] = data['email']
    if 'password' in data:
        users[username]['password'] = data['password']
    if '2fa_enabled' in data:
        users[username]['2fa_enabled'] = bool(data['2fa_enabled'])

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)